const size = 40;
const a_range = [];
const b_range = [];
const z_surface = [];

for (let i = 0; i <= size; i++) {
  const a = i * 0.25;
  a_range.push(a);
  const row = [];
  for (let j = 0; j <= size; j++) {
    const b = j * 0.25;
    if (i === 0) b_range.push(b);
    // The identity (a+b)^2
    row.push(Math.pow(a + b, 2));
  }
  z_surface.push(row);
}

// Create a trace for the surface
const surfaceTrace = {
  z: z_surface,
  x: a_range,
  y: b_range,
  type: 'surface',
  colorscale: 'Viridis',
  showscale: true,
  name: '(a+b)²',
  contours: {
    z: { show: true, usecolormap: true, highlightcolor: '#ef4444', project: { z: true } }
  },
  colorbar: {
    title: 'Area',
    titlefont: { color: '#cbd5e1' },
    tickfont: { color: '#cbd5e1' }
  }
};

// Trace to highlight a specific point, e.g., a=5, b=5
const pointTrace = {
  x: [5],
  y: [5],
  z: [Math.pow(5+5, 2)],
  mode: 'markers+text',
  type: 'scatter3d',
  marker: { size: 8, color: '#ef4444' },
  text: ['(5+5)² = 100'],
  textposition: 'top center',
  name: 'Sample Point',
  font: { color: '#ffffff' }
};

return [surfaceTrace, pointTrace];
